// // This module performs an OR operation on two input signals, in1 and in2, under the control of an enable signal, en. The output, out, reflects the result of the OR operation only when en is high; otherwise, it becomes LOW.
module top_module(
    in1,
    in2,
    en,
    out,
    out_valid
);input in1;
    input in2;
    input en;
    output out;
    output out_valid;

    wire and_out;

    and and_gate(and_out, in1, in2);

    assign out = and_out & en;
    assign out_valid = en;

endmodule
